const topic = $.input.researchTopic;
const depth = $.input.depth || 'comprehensive';
const maxQueries = depth === 'quick' ? 3 : depth === 'standard' ? 5 : 8;

const baseQueries = [
  topic + ' overview comprehensive analysis',
  topic + ' latest developments ' + new Date().getFullYear(),
  topic + ' expert opinions research findings',
  topic + ' market trends data statistics',
  topic + ' challenges problems limitations',
  topic + ' future predictions outlook',
  topic + ' case studies examples real-world',
  topic + ' comparison alternatives landscape'
];

const queries = baseQueries.slice(0, maxQueries);
return { queries, queryCount: queries.length, topic, today: new Date().toISOString().split('T')[0] };

const iterations = $.steps.searchAll.response.iterations || [];
const allResults = [];
const seenUrls = new Set();

iterations.forEach(iter => {
  const results = (iter.searchExa && iter.searchExa.response) ? (iter.searchExa.response.results || iter.searchExa.response.data || []) : [];
  results.forEach(r => {
    if (r.url && !seenUrls.has(r.url)) {
      seenUrls.add(r.url);
      allResults.push({ url: r.url, title: r.title || '', text: (r.text || r.content || '').slice(0, 2000) });
    }
  });
});

const topUrls = allResults.slice(0, 5).map(r => r.url);
let searchContent = '';
allResults.slice(0, 20).forEach((r, i) => {
  searchContent += 'SOURCE ' + (i + 1) + ': ' + r.title + '\n';
  searchContent += 'URL: ' + r.url + '\n';
  searchContent += r.text.slice(0, 1500) + '\n\n';
});

return { topUrls, searchContent, totalResults: allResults.length };

let compiled = $.steps.collectTopUrls.output.searchContent;

const topUrls = $.steps.collectTopUrls.output.topUrls;
const scrapeIters = $.steps.deepScrape.response.iterations || [];

compiled += '\n=== DEEP SCRAPED CONTENT ===\n\n';
scrapeIters.forEach((iter, i) => {
  const resp = (iter.scrape && iter.scrape.response && iter.scrape.response.data) ? iter.scrape.response.data : null;
  if (resp && resp.markdown) {
    compiled += 'DEEP SOURCE ' + (i + 1) + ' (' + (topUrls[i] || 'unknown') + '):\n';
    compiled += resp.markdown.slice(0, 3000) + '\n\n';
  }
});

return { compiled: compiled.slice(0, 25000), totalSources: $.steps.collectTopUrls.output.totalResults };

const d = $.steps.compileAllResearch.output;
const q = $.steps.generateQueries.output;

let prompt = 'You are a senior research analyst. Synthesize the following research data into a comprehensive, well-structured report on: ' + q.topic + '\n\n';
prompt += 'DATE: ' + q.today + '\n';
prompt += 'TOTAL SOURCES ANALYZED: ' + d.totalSources + '\n\n';
prompt += 'RESEARCH DATA:\n' + d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Create a thorough, well-structured research report\n';
prompt += '- Include an executive summary, key findings, detailed analysis, and conclusions\n';
prompt += '- Cite sources where possible\n';
prompt += '- Include data points, statistics, and evidence\n';
prompt += '- Identify knowledge gaps and areas for further research\n';
prompt += '- Be objective and balanced\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "Research Report: ' + q.topic + '",\n';
prompt += '  "executiveSummary": "3-5 sentence overview",\n';
prompt += '  "keyFindings": ["finding 1", "finding 2", "finding 3"],\n';
prompt += '  "sections": [\n';
prompt += '    { "heading": "Section Title", "content": "detailed content with evidence" }\n';
prompt += '  ],\n';
prompt += '  "dataPoints": [{ "stat": "number or fact", "source": "where from" }],\n';
prompt += '  "conclusions": ["conclusion 1"],\n';
prompt += '  "futureOutlook": "predictions and trends",\n';
prompt += '  "knowledgeGaps": ["gap 1"],\n';
prompt += '  "sources": ["url1", "url2"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Research Report', executiveSummary: raw.slice(0, 500), keyFindings: [], sections: [{ heading: 'Report', content: raw }], dataPoints: [], conclusions: [], futureOutlook: '', knowledgeGaps: [], sources: [] }; }

const ai = $.steps.parseAI.output;
const MAX_BLOCK = 1900;

function splitText(text, max) {
  const chunks = [];
  let remaining = text || '';
  while (remaining.length > 0) {
    if (remaining.length <= max) { chunks.push(remaining); break; }
    let splitAt = remaining.lastIndexOf('. ', max);
    if (splitAt < max * 0.5) splitAt = remaining.lastIndexOf(' ', max);
    if (splitAt < max * 0.3) splitAt = max;
    chunks.push(remaining.slice(0, splitAt + 1).trim());
    remaining = remaining.slice(splitAt + 1).trim();
  }
  return chunks;
}

const children = [];

children.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ type: 'text', text: { content: 'Executive Summary' } }] } });
splitText(ai.executiveSummary || '', MAX_BLOCK).forEach(chunk => {
  children.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: chunk } }] } });
});

if (ai.keyFindings && ai.keyFindings.length > 0) {
  children.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ type: 'text', text: { content: 'Key Findings' } }] } });
  ai.keyFindings.forEach(f => {
    children.push({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: [{ type: 'text', text: { content: f.slice(0, MAX_BLOCK) } }] } });
  });
}

if (ai.sections && ai.sections.length > 0) {
  ai.sections.forEach(section => {
    children.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ type: 'text', text: { content: (section.heading || 'Section').slice(0, MAX_BLOCK) } }] } });
    splitText(section.content || '', MAX_BLOCK).forEach(chunk => {
      children.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: chunk } }] } });
    });
  });
}

if (ai.dataPoints && ai.dataPoints.length > 0) {
  children.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ type: 'text', text: { content: 'Key Data Points' } }] } });
  ai.dataPoints.forEach(dp => {
    const text = (dp.stat || '') + (dp.source ? ' (Source: ' + dp.source + ')' : '');
    children.push({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: [{ type: 'text', text: { content: text.slice(0, MAX_BLOCK) } }] } });
  });
}

if (ai.conclusions && ai.conclusions.length > 0) {
  children.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ type: 'text', text: { content: 'Conclusions' } }] } });
  ai.conclusions.forEach(c => {
    children.push({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: [{ type: 'text', text: { content: c.slice(0, MAX_BLOCK) } }] } });
  });
}

if (ai.futureOutlook) {
  children.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ type: 'text', text: { content: 'Future Outlook' } }] } });
  splitText(ai.futureOutlook, MAX_BLOCK).forEach(chunk => {
    children.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: chunk } }] } });
  });
}

if (ai.knowledgeGaps && ai.knowledgeGaps.length > 0) {
  children.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ type: 'text', text: { content: 'Knowledge Gaps' } }] } });
  ai.knowledgeGaps.forEach(g => {
    children.push({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: [{ type: 'text', text: { content: g.slice(0, MAX_BLOCK) } }] } });
  });
}

if (ai.sources && ai.sources.length > 0) {
  children.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ type: 'text', text: { content: 'Sources' } }] } });
  ai.sources.forEach(s => {
    children.push({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: [{ type: 'text', text: { content: s.slice(0, MAX_BLOCK) } }] } });
  });
}

return { title: ai.title || 'Research Report', children: children.slice(0, 100) };
